mapper.update:
UPDATE sch_calendar_event
SET title = #{title}, description = #{description},
    start_time = #{startTime}, end_time = #{endTime}, event_type = #{eventType}
WHERE id = #{id}

mapper.select:

SELECT * FROM sch_calendar_event
WHERE user_id = #{userId}
AND start_time >= #{start}
AND end_time <= #{end}
ORDER BY start_time

mapper.update:
UPDATE sch_task
SET title = #{title}, due_date = #{dueDate},
    priority = #{priority}, status = #{status}
WHERE id = #{id}

mapper.select:
SELECT * FROM sch_task WHERE assignee_id = #{assigneeId}
AND status = #{status}
ORDER BY due_date
